import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface UpcomingMeeting {
  title: string;
  time: string;
  location: string;
}

interface AgendaData {
  upcomingMeetings: UpcomingMeeting[];
}

export default function Widget() {
  const agendaData = response.data as AgendaData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B',
        borderColor: primaryColor,
        borderWidth: 2,
        borderStyle: 'solid'
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: primaryColor }}>
            Upcoming Meetings
          </Typography>
          <Stack spacing={1}>
            {agendaData.upcomingMeetings.map((meeting, index) => (
              <Box key={index}>
                <Typography variant="body1" sx={{ fontWeight: 600, color: primaryColor }}>
                  {meeting.title}
                </Typography>
                <Typography variant="body2" sx={{ color: accentColor }}>
                  {meeting.time} - {meeting.location}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
